import React, { useState } from "react";

export const AppContext = React.createContext({
  selectedSidebarItem: null,
  setSelectedSidebarItem: () => {},
  selectedTab: null,
  setSelectedTab: () => {},

});

export const AppContextProvider = (props) => {
  const [selectedSidebarItem, setSelectedSidebarItem] = useState("Direct-Message");
  const [selectedTab, setSelectedTab] = useState("Online");

  const setSelectedSidebarItemHandler = (id) => {
    setSelectedSidebarItem(id);
  };

  const setSelectedTabHandler = (title) => {
    setSelectedTab(title)
  }


  return (
    <AppContext.Provider
      value={{
        selectedSidebarItem: selectedSidebarItem,
        setSelectedSidebarItem: setSelectedSidebarItemHandler,
        selectedTab: selectedTab,
        setSelectedTab: setSelectedTabHandler,
      }}
    >
      {props.children}
    </AppContext.Provider>
  );
};
